  6: interface OverviewMetricsRow {
  7:   today_cents: string;
  8:   week_cents: string;
  9:   month_cents: string;
 10:   page_views_total: string;
 11:   add_to_cart_total: string;
 12:   remove_from_cart_total: string;
 13:   checkout_started_total: string;
 14:   purchases_total: string;
 15: }
 16: 
 17: interface TopProductRow {
 18:   product_id: string;
 19:   revenue_cents: string;
 20:   purchase_count: string;
 21: }
 22: 
 23: interface RecentActivityRow {
 24:   event_id: string;
 25:   event_type: string;
 26:   occurred_at: Date;
 27:   product_id: string | null;
 28:   amount_cents: number | null;
 29:   currency: string | null;
 30: }
 31: 
 32: interface TrendRow {
 33:   bucket_date: string;
 34:   revenue_cents: string;
 35:   purchases: string;
 36:   page_views: string;
 37: }
