 39: @Injectable()
 40: export class AnalyticsRepository {
 41:   constructor(
 42:     private readonly db: DbService,
 43:     private readonly storesRepository: StoresRepository,
 44:   ) {}
 45: 
 46:   async getOverview(storeId: string) {
 47:     const store = await this.storesRepository.findStoreById(storeId);
 48:     if (!store) {
 49:       throw new NotFoundException('Store not found');
 50:     }
 51: 
 52:     const result = await this.db.query<OverviewMetricsRow>(
 53:       `
 54:         WITH bounds AS (
 55:           SELECT
 56:             (NOW() AT TIME ZONE $2)::date AS today,
 57:             date_trunc('week', NOW() AT TIME ZONE $2)::date AS week_start,
 58:             date_trunc('month', NOW() AT TIME ZONE $2)::date AS month_start
 59:         )
 60:         SELECT
 61:           COALESCE(SUM(revenue_cents) FILTER (WHERE bucket_date = bounds.today), 0)::bigint AS today_cents,
 62:           COALESCE(SUM(revenue_cents) FILTER (WHERE bucket_date >= bounds.week_start), 0)::bigint AS week_cents,
 63:           COALESCE(SUM(revenue_cents) FILTER (WHERE bucket_date >= bounds.month_start), 0)::bigint AS month_cents,
 64:           COALESCE(SUM(page_views), 0)::bigint AS page_views_total,
 65:           COALESCE(SUM(add_to_cart), 0)::bigint AS add_to_cart_total,
 66:           COALESCE(SUM(remove_from_cart), 0)::bigint AS remove_from_cart_total,
 67:           COALESCE(SUM(checkout_started), 0)::bigint AS checkout_started_total,
 68:           COALESCE(SUM(purchases), 0)::bigint AS purchases_total
 69:         FROM store_daily_metrics
 70:         CROSS JOIN bounds
 71:         WHERE store_id = $1
 72:       `,
 73:       [storeId, store.timezone],
 74:     );
 75: 
 76:     const metrics = result.rows[0];
 77:     const pageViews = Number(metrics?.page_views_total ?? 0);
 78:     const purchases = Number(metrics?.purchases_total ?? 0);
 79: 
 80:     return {
 81:       revenue: {
 82:         todayCents: Number(metrics?.today_cents ?? 0),
 83:         weekCents: Number(metrics?.week_cents ?? 0),
 84:         monthCents: Number(metrics?.month_cents ?? 0),
 85:         currency: store.currency,
 86:       },
 87:       eventCounts: {
 88:         page_view: pageViews,
 89:         add_to_cart: Number(metrics?.add_to_cart_total ?? 0),
 90:         remove_from_cart: Number(metrics?.remove_from_cart_total ?? 0),
 91:         checkout_started: Number(metrics?.checkout_started_total ?? 0),
 92:         purchase: purchases,
 93:       },
 94:       conversionRate: pageViews === 0 ? 0 : Number((purchases / pageViews).toFixed(4)),
 95:       lastUpdatedAt: new Date().toISOString(),
 96:     };
 97:   }
 98: 
 99:   async getTopProducts(storeId: string, query: AnalyticsQueryDto) {
100:     const store = await this.storesRepository.findStoreById(storeId);
101:     if (!store) {
102:       throw new NotFoundException('Store not found');
103:     }
104: 
105:     const boundsResult = await this.db.query<{
106:       today: string;
107:       week_start: string;
108:       month_start: string;
109:     }>(
110:       `
111:         SELECT
112:           (NOW() AT TIME ZONE $2)::date::text AS today,
113:           date_trunc('week', NOW() AT TIME ZONE $2)::date::text AS week_start,
114:           date_trunc('month', NOW() AT TIME ZONE $2)::date::text AS month_start
115:         FROM stores
116:         WHERE id = $1
117:       `,
118:       [storeId, store.timezone],
119:     );
120: 
121:     const bounds = boundsResult.rows[0];
122:     const startDate =
123:       query.range === 'today'
124:         ? bounds.today
125:         : query.range === 'week'
126:           ? bounds.week_start
127:           : bounds.month_start;
128: 
129:     const result = await this.db.query<TopProductRow>(
130:       `
131:         SELECT
132:           product_id,
133:           SUM(revenue_cents)::bigint AS revenue_cents,
134:           SUM(purchase_count)::bigint AS purchase_count
135:         FROM product_daily_revenue
136:         WHERE store_id = $1
137:           AND bucket_date >= $2::date
138:         GROUP BY product_id
139:         ORDER BY revenue_cents DESC, purchase_count DESC
140:         LIMIT 10
141:       `,
142:       [storeId, startDate],
143:     );
144: 
145:     return {
146:       range: query.range,
147:       currency: store.currency,
148:       items: result.rows.map((row) => ({
149:         productId: row.product_id,
150:         revenueCents: Number(row.revenue_cents),
151:         purchaseCount: Number(row.purchase_count),
152:       })),
153:     };
154:   }
155: 
156:   async getRecentActivity(storeId: string) {
157:     const result = await this.db.query<RecentActivityRow>(
158:       `
159:         SELECT
160:           event_id,
161:           event_type,
162:           occurred_at,
163:           product_id,
164:           amount_cents,
165:           currency
166:         FROM events
167:         WHERE store_id = $1
168:         ORDER BY occurred_at DESC
169:         LIMIT 20
170:       `,
171:       [storeId],
172:     );
173: 
174:     return {
175:       items: result.rows.map((row) => ({
176:         eventId: row.event_id,
177:         eventType: row.event_type,
178:         occurredAt: row.occurred_at.toISOString(),
179:         productId: row.product_id,
180:         amountCents: row.amount_cents,
181:         currency: row.currency,
182:       })),
183:     };
184:   }
185: 
186:   async getTrend(storeId: string, days: number) {
187:     const store = await this.storesRepository.findStoreById(storeId);
188:     if (!store) {
189:       throw new NotFoundException('Store not found');
190:     }
191: 
192:     const result = await this.db.query<TrendRow>(
193:       `
194:         WITH bounds AS (
195:           SELECT (NOW() AT TIME ZONE $2)::date AS today
196:         ),
197:         series AS (
198:           SELECT generate_series(
199:             (SELECT today FROM bounds) - ($3::int - 1),
200:             (SELECT today FROM bounds),
201:             interval '1 day'
202:           )::date AS bucket_date
203:         )
204:         SELECT
205:           series.bucket_date::text,
206:           COALESCE(store_daily_metrics.revenue_cents, 0)::bigint AS revenue_cents,
207:           COALESCE(store_daily_metrics.purchases, 0)::bigint AS purchases,
208:           COALESCE(store_daily_metrics.page_views, 0)::bigint AS page_views
209:         FROM series
210:         LEFT JOIN store_daily_metrics
211:           ON store_daily_metrics.store_id = $1
212:          AND store_daily_metrics.bucket_date = series.bucket_date
213:         ORDER BY series.bucket_date ASC
214:       `,
215:       [storeId, store.timezone, days],
216:     );
217: 
218:     return {
219:       currency: store.currency,
220:       items: result.rows.map((row) => {
221:         const purchases = Number(row.purchases);
222:         const pageViews = Number(row.page_views);
223: 
224:         return {
225:           date: row.bucket_date,
226:           revenueCents: Number(row.revenue_cents),
227:           purchases,
228:           pageViews,
229:           conversionRate:
230:             pageViews === 0 ? 0 : Number((purchases / pageViews).toFixed(4)),
231:         };
232:       }),
233:     };
234:   }
