17: @Injectable()
18: export class AuthService {
19:   constructor(
20:     private readonly db: DbService,
21:     private readonly jwtService: JwtService,
22:   ) {}
23: 
24:   async login(dto: LoginDto) {
25:     const result = await this.db.query<LoginRow>(
26:       `
27:         SELECT
28:           users.id AS user_id,
29:           users.email,
30:           users.password_hash,
31:           stores.id AS store_id,
32:           stores.name AS store_name,
33:           stores.timezone,
34:           stores.currency
35:         FROM users
36:         INNER JOIN store_memberships
37:           ON store_memberships.user_id = users.id
38:         INNER JOIN stores
39:           ON stores.id = store_memberships.store_id
40:         WHERE users.email = $1
41:         LIMIT 1
42:       `,
43:       [dto.email.toLowerCase()],
44:     );
45: 
46:     const row = result.rows[0];
47:     if (!row) {
48:       throw new UnauthorizedException('Invalid credentials');
49:     }
50: 
51:     const passwordMatches = await bcrypt.compare(dto.password, row.password_hash);
52:     if (!passwordMatches) {
53:       throw new UnauthorizedException('Invalid credentials');
54:     }
55: 
56:     const accessToken = await this.jwtService.signAsync({
57:       sub: row.user_id,
58:       email: row.email,
59:       storeId: row.store_id,
60:       storeName: row.store_name,
61:       timezone: row.timezone,
62:       currency: row.currency,
63:     });
64: 
65:     return {
66:       accessToken,
67:       user: {
68:         id: row.user_id,
69:         email: row.email,
70:       },
71:       store: {
72:         id: row.store_id,
73:         name: row.store_name,
74:         timezone: row.timezone,
75:         currency: row.currency,
76:       },
77:     };
78:   }
