9: export class CacheModule {} 1: import { Injectable, Logger, OnModuleDestroy } from '@nestjs/common';
 2: import { ConfigService } from '@nestjs/config';
 3: import Redis from 'ioredis';
 4: 
 5: @Injectable()
 6: export class CacheService implements OnModuleDestroy {
 7:   private readonly logger = new Logger(CacheService.name);
 8:   private readonly client: Redis;
 9: 
10:   constructor(configService: ConfigService) {
11:     this.client = new Redis(configService.get<string>('REDIS_URL') ?? 'redis://localhost:6379', {
12:       lazyConnect: true,
13:       maxRetriesPerRequest: 1,
14:       enableOfflineQueue: false,
15:     });
16: 
17:     this.client.on('error', (error) => {
18:       this.logger.debug(`Redis unavailable: ${error.message}`);
19:     });
20:   }
21: 
22:   async getJson<T>(key: string): Promise<T | null> {
23:     try {
24:       await this.ensureConnection();
25:       const raw = await this.client.get(key);
26:       return raw ? (JSON.parse(raw) as T) : null;
27:     } catch {
28:       return null;
29:     }
30:   }
31: 
32:   async setJson(key: string, value: unknown, ttlSeconds = 10): Promise<void> {
33:     try {
34:       await this.ensureConnection();
35:       await this.client.set(key, JSON.stringify(value), 'EX', ttlSeconds);
36:     } catch {
37:       return;
38:     }
39:   }
40: 
41:   async del(...keys: string[]): Promise<void> {
42:     if (keys.length === 0) {
43:       return;
44:     }
45: 
46:     try {
47:       await this.ensureConnection();
48:       await this.client.del(...keys);
49:     } catch {
50:       return;
51:     }
52:   }
53: 
54:   async onModuleDestroy() {
55:     try {
56:       if (this.client.status !== 'end') {
57:         await this.client.quit();
58:       }
59:     } catch {
60:       return;
61:     }
62:   }
63: 
64:   private async ensureConnection() {
65:     if (this.client.status === 'wait') {
66:       await this.client.connect();
67:     }
68:   }
