 9: @Catch()
10: export class HttpExceptionFilter implements ExceptionFilter {
11:   catch(exception: unknown, host: ArgumentsHost) {
12:     const ctx = host.switchToHttp();
13:     const response = ctx.getResponse();
14: 
15:     if (exception instanceof HttpException) {
16:       const status = exception.getStatus();
17:       const body = exception.getResponse();
18:       const message =
19:         typeof body === 'string'
20:           ? body
21:           : Array.isArray((body as { message?: unknown }).message)
22:             ? (body as { message: string[] }).message.join(', ')
23:             : ((body as { message?: string }).message ?? exception.message);
24: 
25:       response.status(status).json({
26:         statusCode: status,
27:         message,
28:         error:
29:           typeof body === 'string'
30:             ? exception.name
31:             : ((body as { error?: string }).error ?? exception.name),
32:       });
33:       return;
34:     }
35: 
36:     response.status(HttpStatus.INTERNAL_SERVER_ERROR).json({
37:       statusCode: HttpStatus.INTERNAL_SERVER_ERROR,
38:       message: 'Internal server error',
39:     });
40:   }
