161: function buildSeedEvents(): SeedEvent[] {
162:   const now = new Date();
163:   let sequence = 1;
164:   const events: SeedEvent[] = [];
165: 
166:   stores.forEach((store, storeIndex) => {
167:     for (let dayOffset = 0; dayOffset < 28; dayOffset += 1) {
168:       const dayDate = new Date(now);
169:       dayDate.setUTCDate(now.getUTCDate() - dayOffset);
170:       dayDate.setUTCHours(14 + storeIndex, 0, 0, 0);
171: 
172:       const pageViews = 18 + ((dayOffset + storeIndex) % 6) * 2;
173:       const addToCart = 6 + ((dayOffset + storeIndex) % 4);
174:       const removeFromCart = 1 + (dayOffset % 2);
175:       const checkoutStarted = 4 + ((dayOffset + storeIndex) % 3);
176:       const purchases = 3 + ((dayOffset + storeIndex) % 3);
177: 
178:       pushEvents(events, {
179:         count: pageViews,
180:         dayDate,
181:         eventType: 'page_view',
182:         storeId: store.id,
183:         sequenceStart: sequence,
184:       });
185:       sequence += pageViews;
186: 
187:       pushEvents(events, {
188:         count: addToCart,
189:         dayDate,
190:         eventType: 'add_to_cart',
191:         storeId: store.id,
192:         sequenceStart: sequence,
193:       });
194:       sequence += addToCart;
195: 
196:       pushEvents(events, {
197:         count: removeFromCart,
198:         dayDate,
199:         eventType: 'remove_from_cart',
200:         storeId: store.id,
201:         sequenceStart: sequence,
202:       });
203:       sequence += removeFromCart;
204: 
205:       pushEvents(events, {
206:         count: checkoutStarted,
207:         dayDate,
208:         eventType: 'checkout_started',
209:         storeId: store.id,
210:         sequenceStart: sequence,
211:       });
212:       sequence += checkoutStarted;
213: 
214:       for (let purchaseIndex = 0; purchaseIndex < purchases; purchaseIndex += 1) {
215:         const product = products[(purchaseIndex + dayOffset + storeIndex) % products.length];
216:         const occurredAt = new Date(dayDate);
217:         occurredAt.setUTCMinutes(40 + purchaseIndex * 3);
218:         const eventId = `evt_${String(sequence).padStart(6, '0')}`;
219: 
220:         events.push({
221:           eventId,
222:           storeId: store.id,
223:           eventType: 'purchase',
224:           occurredAt: occurredAt.toISOString(),
225:           productId: product.id,
226:           amountCents: product.amountCents,
227:           currency: store.currency,
228:           rawData: {
229:             product_id: product.id,
230:             amount: product.amountCents / 100,
231:             currency: store.currency,
232:           },
233:         });
234: 
235:         sequence += 1;
236:       }
237:     }
238:   });
239: 
240:   return events;
241: }
242: 
243: function pushEvents(
244:   events: SeedEvent[],
245:   input: {
246:     count: number;
247:     dayDate: Date;
248:     eventType: SeedEvent['eventType'];
249:     storeId: string;
250:     sequenceStart: number;
251:   },
252: ) {
253:   for (let index = 0; index < input.count; index += 1) {
254:     const occurredAt = new Date(input.dayDate);
255:     occurredAt.setUTCMinutes(index);
256: 
257:     events.push({
258:       eventId: `evt_${String(input.sequenceStart + index).padStart(6, '0')}`,
259:       storeId: input.storeId,
260:       eventType: input.eventType,
261:       occurredAt: occurredAt.toISOString(),
262:       productId: null,
263:       amountCents: null,
264:       currency: null,
265:       rawData: {},
266:     });
267:   }
268: }
