270: async function insertEvents(client: PoolClient, events: SeedEvent[]) {
271:   const values: unknown[] = [];
272:   const placeholders = events.map((event, index) => {
273:     const offset = index * 8;
274:     values.push(
275:       event.eventId,
276:       event.storeId,
277:       event.eventType,
278:       event.occurredAt,
279:       event.productId,
280:       event.amountCents,
281:       event.currency,
282:       JSON.stringify(event.rawData),
283:     );
284: 
285:     return `($${offset + 1}, $${offset + 2}, $${offset + 3}, $${offset + 4}::timestamptz, $${offset + 5}, $${offset + 6}, $${offset + 7}, $${offset + 8}::jsonb)`;
286:   });
287: 
288:   await client.query(
289:     `
290:       INSERT INTO events (
291:         event_id,
292:         store_id,
293:         event_type,
294:         occurred_at,
295:         product_id,
296:         amount_cents,
297:         currency,
298:         raw_data
299:       )
300:       VALUES ${placeholders.join(',\n')}
301:     `,
302:     values,
303:   );
