 23:   constructor(
 24:     private readonly db: DbService,
 25:     private readonly storesRepository: StoresRepository,
 26:   ) {}
 27: 
 28:   async applyEvent(
 29:     storeId: string,
 30:     dto: IngestEventDto,
 31:     client?: DbTransactionClient,
 32:   ) {
 33:     const store = await this.storesRepository.findStoreById(storeId);
 34:     if (!store) {
 35:       throw new NotFoundException('Store not found');
 36:     }
 37: 
 38:     const amountCents =
 39:       typeof dto.data.amount === 'number' ? Math.round(dto.data.amount * 100) : 0;
 40: 
 41:     if (dto.event_type === 'purchase') {
 42:       if (typeof dto.data.amount !== 'number') {
 43:         throw new BadRequestException('Purchase events require an amount');
 44:       }
 45: 
 46:       if (!dto.data.currency) {
 47:         throw new BadRequestException('Purchase events require a currency');
 48:       }
 49: 
 50:       if (dto.data.currency !== store.currency) {
 51:         throw new BadRequestException('Purchase currency does not match store currency');
 52:       }
 53:     }
 54: 
 55:     const bucketDate = getBucketDate(dto.timestamp, store.timezone);
 56:     const column = eventColumnMap[dto.event_type];
 57:     const upsertStoreMetricsSql = `
 58:       INSERT INTO store_daily_metrics (
 59:         store_id,
 60:         bucket_date,
 61:         ${column},
 62:         revenue_cents
 63:       )
 64:       VALUES ($1, $2::date, 1, $3)
 65:       ON CONFLICT (store_id, bucket_date)
 66:       DO UPDATE SET
 67:         ${column} = store_daily_metrics.${column} + 1,
 68:         revenue_cents = store_daily_metrics.revenue_cents + EXCLUDED.revenue_cents
 69:     `;
 70:     const storeMetricsParams = [
 71:       storeId,
 72:       bucketDate,
 73:       dto.event_type === 'purchase' ? amountCents : 0,
 74:     ];
 75: 
 76:     if (client) {
 77:       await client.query(upsertStoreMetricsSql, storeMetricsParams);
 78:     } else {
 79:       await this.db.query(upsertStoreMetricsSql, storeMetricsParams);
 80:     }
 81: 
 82:     if (dto.event_type !== 'purchase' || !dto.data.product_id) {
 83:       return;
 84:     }
 85: 
 86:     const upsertProductRevenueSql = `
 87:       INSERT INTO product_daily_revenue (
 88:         store_id,
 89:         product_id,
 90:         bucket_date,
 91:         purchase_count,
 92:         revenue_cents
 93:       )
 94:       VALUES ($1, $2, $3::date, 1, $4)
 95:       ON CONFLICT (store_id, product_id, bucket_date)
 96:       DO UPDATE SET
 97:         purchase_count = product_daily_revenue.purchase_count + 1,
 98:         revenue_cents = product_daily_revenue.revenue_cents + EXCLUDED.revenue_cents
 99:     `;
100:     const productRevenueParams = [storeId, dto.data.product_id, bucketDate, amountCents];
101: 
102:     if (client) {
103:       await client.query(upsertProductRevenueSql, productRevenueParams);
104:     } else {
105:       await this.db.query(upsertProductRevenueSql, productRevenueParams);
106:     }
107:   }
108: }
