110: function getBucketDate(timestamp: string, timeZone: string): string {
111:   const date = new Date(timestamp);
112:   const formatter = new Intl.DateTimeFormat('en-CA', {
113:     timeZone,
114:     year: 'numeric',
115:     month: '2-digit',
116:     day: '2-digit',
117:   });
118:   const parts = formatter.formatToParts(date);
119: 
120:   const year = parts.find((part) => part.type === 'year')?.value;
121:   const month = parts.find((part) => part.type === 'month')?.value;
122:   const day = parts.find((part) => part.type === 'day')?.value;
123: 
124:   if (!year || !month || !day) {
125:     throw new Error('Unable to derive bucket date');
126:   }
127: 
128:   return `${year}-${month}-${day}`;
