22:   test('rejects a payload whose store_id does not match the authenticated store', async () => {
23:     let transactionCalls = 0;
24: 
25:     const service = new EventsService(
26:       { del: async () => undefined } as never,
27:       {
28:         withTransaction: async () => {
29:           transactionCalls += 1;
30:         },
31:       } as never,
32:       { insertEvent: async () => undefined } as never,
33:       { applyEvent: async () => undefined } as never,
34:     );
35: 
36:     await expect(
37:       service.ingest('store_1', buildEvent({ store_id: 'store_2' })),
