48:       {
49:         del: async () => {
50:           cacheInvalidations += 1;
51:         },
52:       } as never,
53:       {
54:         withTransaction: async (
55:           operation: (client: unknown) => Promise<unknown>,
56:         ) => operation({}),
57:       } as never,
58:       {
59:         insertEvent: async () => {
60:           throw new ConflictException('duplicate event');
61:         },
62:       } as never,
63:       {
64:         applyEvent: async () => {
65:           rollupCalls += 1;
66:         },
67:       } as never,
68:     );
69: 
70:     await expect(service.ingest('store_1', buildEvent())).rejects.toThrow(
71:       ConflictException,
72:     );
73: 
74:     expect(rollupCalls).toBe(0);
