13: export class ApiError extends Error {
14:   constructor(
15:     message: string,
16:     public readonly status: number
17:   ) {
18:     super(message);
19:     this.name = "ApiError";
20:   }
21: }
22: 
23: async function readErrorMessage(response: Response) {
24:   try {
25:     const payload = (await response.json()) as ApiErrorResponse;
26:     return payload.message ?? `Request failed with status ${response.status}`;
27:   } catch {
28:     return `Request failed with status ${response.status}`;
29:   }
30: }
31: 
32: export async function fetchJson<T>(path: string, init?: RequestInit): Promise<T> {
33:   const response = await fetch(`${API_BASE_URL}${path}`, {
34:     ...init,
35:     cache: "no-store",
36:     headers: {
37:       "Content-Type": "application/json",
38:       ...(init?.headers ?? {})
39:     }
40:   });
41: 
42:   if (!response.ok) {
43:     throw new ApiError(await readErrorMessage(response), response.status);
44:   }
45: 
46:   return response.json() as Promise<T>;
47: }
