10:   const timestamp = new Date(input).getTime();
11:   const diffSeconds = Math.max(0, Math.round((Date.now() - timestamp) / 1000));
12: 
13:   if (diffSeconds < 60) {
14:     return `${diffSeconds}s ago`;
15:   }
16: 
17:   const diffMinutes = Math.round(diffSeconds / 60);
18:   if (diffMinutes < 60) {
19:     return `${diffMinutes}m ago`;
20:   }
21: 
22:   const diffHours = Math.round(diffMinutes / 60);
23:   if (diffHours < 24) {
24:     return `${diffHours}h ago`;
25:   }
26: 
27:   return `${Math.round(diffHours / 24)}d ago`;
